def get_all_task_templates() -> list[Path]:
    """Get all task templates (from skills/*/templates/task.md and task-doc.md)."""
    templates = []
    for skill_dir in sorted(SKILLS_DIR.iterdir()):
        if not skill_dir.is_dir():
            continue
        tmpl_dir = skill_dir / "templates"
        if tmpl_dir.exists():
            for md_file in sorted(tmpl_dir.glob("*.md")):
                templates.append(md_file)
    return templates


def get_all_record_templates() -> list[Path]:
    """Get all 6 record template files."""
    record_dir = SKILLS_DIR / "submit-task" / "data"
    if record_dir.exists():
        return sorted(record_dir.glob("record-format-*.md"))
    return []

